public double cumulativeProbability(double x) throws MathException {
    final double dev = x - mean;
    final double threshold = 40 * standardDeviation;

    if (Double.isInfinite(dev) || Math.abs(dev) > threshold) {
        return dev < 0 ? 0 : 1;
    }

    try {
        return 0.5 * (1.0 + Erf.erf(dev / (standardDeviation * FastMath.sqrt(2.0))));
    } catch (MaxIterationsExceededException ex) {
        if (x < (mean - 20 * standardDeviation)) {
            return 0;
        } else if (x > (mean + 20 * standardDeviation)) {
            return 1;
        } else {
            throw ex;
        }
    }
}

public double cumulativeProbability(double x) throws MathException {
    final double dev = x - mean;
    final double threshold = standardDeviation * FastMath.sqrt(-2.0 * FastMath.log(Double.MIN_NORMAL));
    try {
        if (dev < -threshold) {
            return 0;
        } else if (dev > threshold) {
            return 1;
        } else {
            return 0.5 * (1.0 + Erf.erf(dev / (standardDeviation * FastMath.sqrt(2.0))));
        }
    } catch (MaxIterationsExceededException ex) {
        if (dev < -threshold) {
            return 0;
        } else if (dev > threshold) {
            return 1;
        } else {
            throw ex;
        }
    }
}
